    fun searchChapters(query: String): List<Chapter> {
        if (query.isBlank()) return fallbackChapters
        return fallbackChapters.filter {
            it.nameSimple.contains(query, ignoreCase = true) ||
            it.translatedName.name.contains(query, ignoreCase = true) ||
            it.nameArabic.contains(query) ||
            it.id.toString() == query.trim()
        }
    }
